import React, { useState, useEffect } from 'react';
import { useAuth } from '../../context/AuthContext';
import { api } from '../../utils/api';
import { getTheme, cardStyle, inputStyle } from '../../utils/theme';
import { PageHeader, StatusBadge, EmptyState, PageLoader, Btn, Modal } from '../../components/common/UI';

const MEDICINES = [
  // Pain Relief
  { id: '1',  name: 'Paracetamol 500mg',      price: 25,  category: 'Pain Relief',     desc: 'For fever & mild pain',            icon: '💊' },
  { id: '2',  name: 'Dolo 650mg',              price: 30,  category: 'Pain Relief',     desc: 'Fever & headache relief',          icon: '💊' },
  { id: '3',  name: 'Ibuprofen 400mg',         price: 40,  category: 'Pain Relief',     desc: 'Anti-inflammatory pain relief',    icon: '💊' },
  { id: '4',  name: 'Aspirin 75mg',            price: 20,  category: 'Pain Relief',     desc: 'Blood thinner & mild pain',        icon: '💊', requiresPrescription: true },
  { id: '5',  name: 'Diclofenac 50mg',         price: 38,  category: 'Pain Relief',     desc: 'Joint & muscle pain',              icon: '💊', requiresPrescription: true },
  { id: '6',  name: 'Naproxen 250mg',          price: 55,  category: 'Pain Relief',     desc: 'Long-lasting pain relief',         icon: '💊', requiresPrescription: true },
  // Antibiotics
  { id: '7',  name: 'Amoxicillin 250mg',       price: 85,  category: 'Antibiotic',      desc: 'Broad-spectrum antibiotic',        icon: '💉', requiresPrescription: true },
  { id: '8',  name: 'Azithromycin 250mg',      price: 110, category: 'Antibiotic',      desc: 'Respiratory infections',           icon: '💉', requiresPrescription: true },
  { id: '9',  name: 'Ciprofloxacin 500mg',     price: 95,  category: 'Antibiotic',      desc: 'Urinary & bacterial infections',   icon: '💉', requiresPrescription: true },
  { id: '10', name: 'Doxycycline 100mg',       price: 78,  category: 'Antibiotic',      desc: 'Broad-spectrum infections',        icon: '💉', requiresPrescription: true },
  { id: '11', name: 'Metronidazole 400mg',     price: 42,  category: 'Antibiotic',      desc: 'Stomach & dental infections',      icon: '💉', requiresPrescription: true },
  { id: '12', name: 'Cefixime 200mg',          price: 135, category: 'Antibiotic',      desc: 'Third-gen cephalosporin',          icon: '💉', requiresPrescription: true },
  // Supplements
  { id: '13', name: 'Vitamin C 1000mg',        price: 120, category: 'Supplement',      desc: 'Immune system support',            icon: '🍊' },
  { id: '14', name: 'Vitamin D3 60K IU',       price: 180, category: 'Supplement',      desc: 'Bone health & immunity',           icon: '☀️' },
  { id: '15', name: 'Multivitamin Daily',      price: 220, category: 'Supplement',      desc: 'Complete daily nutrition',         icon: '🌈' },
  { id: '16', name: 'Vitamin B12 500mcg',      price: 145, category: 'Supplement',      desc: 'Nerve & energy support',           icon: '⚡' },
  { id: '17', name: 'Calcium + D3 500mg',      price: 160, category: 'Supplement',      desc: 'Bone strength',                    icon: '🦴' },
  { id: '18', name: 'Omega-3 Fish Oil 1000mg', price: 280, category: 'Supplement',      desc: 'Heart & brain health',             icon: '🐟' },
  { id: '19', name: 'Zinc 50mg',               price: 90,  category: 'Supplement',      desc: 'Immunity & wound healing',         icon: '🛡️' },
  { id: '20', name: 'Iron 65mg + Folic Acid',  price: 75,  category: 'Supplement',      desc: 'Anaemia & pregnancy support',      icon: '🩸' },
  { id: '21', name: 'Magnesium 250mg',         price: 195, category: 'Supplement',      desc: 'Muscle & sleep support',           icon: '💤' },
  // Antacid / GI
  { id: '22', name: 'Omeprazole 20mg',         price: 65,  category: 'Antacid',         desc: 'For acidity & GERD',               icon: '🟡' },
  { id: '23', name: 'Pantoprazole 40mg',       price: 55,  category: 'Antacid',         desc: 'Gastric acid reducer',             icon: '🔵' },
  { id: '24', name: 'Ranitidine 150mg',        price: 30,  category: 'Antacid',         desc: 'Heartburn & ulcer relief',         icon: '🟡' },
  { id: '25', name: 'Domperidone 10mg',        price: 35,  category: 'Antacid',         desc: 'Nausea & vomiting',                icon: '🟢' },
  { id: '26', name: 'Loperamide 2mg',          price: 28,  category: 'Antacid',         desc: 'Anti-diarrhoeal',                  icon: '🔴' },
  { id: '27', name: 'ORS Electrolyte Sachet',  price: 15,  category: 'Antacid',         desc: 'Rehydration solution',             icon: '💧' },
  // Allergy / Respiratory
