export default function Medicines() {
  const { darkMode } = useAuth();
  const t = getTheme(darkMode);
  const [orders, setOrders] = useState([]);
  const [cart, setCart] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState('shop');
  const [search, setSearch] = useState('');
  const [catFilter, setCatFilter] = useState('All');
  const [showCheckout, setShowCheckout] = useState(false);
  const [buyNowItem, setBuyNowItem] = useState(null);
  const [address, setAddress] = useState('');
  const [notes, setNotes] = useState('');
  const [placing, setPlacing] = useState(false);
  const [success, setSuccess] = useState('');

  useEffect(() => { api.orders.my().then(r => setOrders(r.data)).catch(() => {}).finally(() => setLoading(false)); }, []);

  const cats = ['All', ...new Set(MEDICINES.map(m => m.category))];
  const filtered = MEDICINES.filter(m => (catFilter === 'All' || m.category === catFilter) && m.name.toLowerCase().includes(search.toLowerCase()));

  const addToCart = (med) => setCart(prev => { const ex = prev.find(i => i.medicineId === med.id); return ex ? prev.map(i => i.medicineId === med.id ? { ...i, quantity: i.quantity + 1 } : i) : [...prev, { medicineId: med.id, name: med.name, price: med.price, category: med.category, requiresPrescription: med.requiresPrescription || false, quantity: 1 }]; });
  const removeFromCart = (id) => setCart(prev => prev.filter(i => i.medicineId !== id));
  const updateQty = (id, qty) => { if (qty < 1) return removeFromCart(id); setCart(prev => prev.map(i => i.medicineId === id ? { ...i, quantity: qty } : i)); };
  const total = cart.reduce((s, i) => s + i.price * i.quantity, 0);
  const cartCount = cart.reduce((s, i) => s + i.quantity, 0);

  const checkoutItems = buyNowItem ? [{ medicineId: buyNowItem.id, name: buyNowItem.name, price: buyNowItem.price, category: buyNowItem.category, requiresPrescription: buyNowItem.requiresPrescription || false, quantity: 1 }] : cart;
  const checkoutTotal = checkoutItems.reduce((s, i) => s + i.price * i.quantity, 0);

  const placeOrder = async () => {
    if (!address.trim()) return alert('Please enter delivery address');
    setPlacing(true);
    try {
      await api.orders.create({ items: checkoutItems, deliveryAddress: address, deliveryNotes: notes });
      setSuccess('✅ Order placed! Pharmacy will confirm shortly.');
      setCart([]); setBuyNowItem(null); setShowCheckout(false); setAddress(''); setNotes('');
      const r = await api.orders.my(); setOrders(r.data);
      setActiveTab('orders'); setTimeout(() => setSuccess(''), 5000);
    } catch (err) { alert(err.response?.data?.error || 'Order failed'); }
    setPlacing(false);
  };

  const inp = inputStyle(t);
  if (loading) return <PageLoader darkMode={darkMode} />;

  return (
    <div style={{ background: t.bg, minHeight: '100vh', padding: 24 }}>
      <div style={{ maxWidth: 1200, margin: '0 auto' }}>
        <PageHeader title="💊 Medicine Delivery" subtitle={`${MEDICINES.length}+ medicines • Same-day delivery`} darkMode={darkMode} />

        {success && <div style={{ background: 'rgba(16,185,129,.1)', border: '1px solid rgba(16,185,129,.3)', color: '#059669', borderRadius: 12, padding: '14px 20px', marginBottom: 20, fontWeight: 600 }}>{success}</div>}

        {/* Tabs */}
        <div style={{ display: 'flex', gap: 8, marginBottom: 24, flexWrap: 'wrap' }}>
          {[{ id: 'shop', label: '🛒 Shop Medicines' }, { id: 'cart', label: `🛒 Cart (${cartCount})` }, { id: 'orders', label: `📦 My Orders (${orders.length})` }].map(tab => (
            <button key={tab.id} onClick={() => setActiveTab(tab.id)} style={{ padding: '10px 20px', borderRadius: 10, border: 'none', cursor: 'pointer', fontWeight: 700, fontSize: 13, background: activeTab === tab.id ? 'linear-gradient(135deg,#0d9488,#059669)' : (darkMode ? 'rgba(255,255,255,0.06)' : 'rgba(0,0,0,0.05)'), color: activeTab === tab.id ? 'white' : t.textSub }}>
              {tab.label}
            </button>
          ))}
        </div>

        {/* SHOP */}
        {activeTab === 'shop' && (
          <>
            <div style={{ display: 'flex', gap: 12, marginBottom: 22, flexWrap: 'wrap' }}>
              <input value={search} onChange={e => setSearch(e.target.value)} placeholder="🔍 Search medicines..." style={{ flex: '1 1 220px', padding: '11px 16px', borderRadius: 10, border: `1px solid ${t.cardBorder}`, background: t.card, color: t.text, fontSize: 14, outline: 'none' }} />
              <select value={catFilter} onChange={e => setCatFilter(e.target.value)} style={{ padding: '11px 16px', borderRadius: 10, border: `1px solid ${t.cardBorder}`, background: t.card, color: t.text, fontSize: 14, outline: 'none', cursor: 'pointer' }}>
                {cats.map(c => <option key={c}>{c}</option>)}
              </select>
            </div>
            <div style={{ color: t.textSub, fontSize: 12, marginBottom: 16 }}>Showing {filtered.length} of {MEDICINES.length} medicines</div>
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill,minmax(220px,1fr))', gap: 16 }}>
              {filtered.map(m => {
                const inCart = cart.find(i => i.medicineId === m.id);
                return (
                  <div key={m.id} style={{ ...cardStyle(t), padding: 18, display: 'flex', flexDirection: 'column' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 10 }}>
                      <div style={{ fontSize: '2rem' }}>{m.icon}</div>
                      {m.requiresPrescription && <span style={{ background: 'rgba(239,68,68,0.1)', color: '#ef4444', fontSize: 9, fontWeight: 800, padding: '2px 8px', borderRadius: 20, textTransform: 'uppercase' }}>Rx Required</span>}
                    </div>
                    <div style={{ fontWeight: 700, color: t.text, fontSize: 13, marginBottom: 3 }}>{m.name}</div>
                    <div style={{ fontSize: 11, color: '#0891b2', marginBottom: 3 }}>{m.category}</div>
                    <div style={{ fontSize: 11, color: t.textSub, marginBottom: 10, flex: 1 }}>{m.desc}</div>
                    <div style={{ fontWeight: 800, color: '#10b981', fontSize: 16, marginBottom: 10 }}>₹{m.price}</div>
                    <div style={{ display: 'flex', gap: 6 }}>
                      {/* Buy Now */}
                      <button onClick={() => { setBuyNowItem(m); setShowCheckout(true); }} style={{ flex: 1, padding: '7px 0', borderRadius: 8, border: 'none', background: 'linear-gradient(135deg,#f59e0b,#d97706)', color: 'white', fontWeight: 700, fontSize: 12, cursor: 'pointer' }}>
                        ⚡ Buy Now
                      </button>
                      {/* Add to Cart */}
                      {inCart ? (
                        <div style={{ display: 'flex', alignItems: 'center', gap: 5 }}>
                          <button onClick={() => updateQty(m.id, inCart.quantity - 1)} style={{ width: 26, height: 26, borderRadius: '50%', border: 'none', background: 'rgba(239,68,68,0.1)', color: '#ef4444', cursor: 'pointer', fontWeight: 800 }}>−</button>
                          <span style={{ fontWeight: 700, color: t.text, minWidth: 16, textAlign: 'center', fontSize: 13 }}>{inCart.quantity}</span>
                          <button onClick={() => updateQty(m.id, inCart.quantity + 1)} style={{ width: 26, height: 26, borderRadius: '50%', border: 'none', background: 'rgba(8,145,178,0.1)', color: '#0891b2', cursor: 'pointer', fontWeight: 800 }}>+</button>
                        </div>
                      ) : (
                        <button onClick={() => addToCart(m)} style={{ flex: 1, padding: '7px 0', borderRadius: 8, border: 'none', background: 'linear-gradient(135deg,#0891b2,#06b6d4)', color: 'white', fontWeight: 700, fontSize: 12, cursor: 'pointer' }}>
                          🛒 Add
                        </button>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </>
        )}

        {/* CART */}
        {activeTab === 'cart' && (
          <div style={{ ...cardStyle(t), padding: 28 }}>
            {cart.length === 0 ? <EmptyState icon="🛒" title="Cart is empty" desc="Add medicines from the shop" darkMode={darkMode} action={<Btn variant="primary" onClick={() => setActiveTab('shop')}>Browse Medicines</Btn>} />
            : (
              <>
                {cart.map(item => (
                  <div key={item.medicineId} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '14px 0', borderBottom: `1px solid ${t.cardBorder}` }}>
                    <div>
                      <div style={{ fontWeight: 700, color: t.text, fontSize: 14 }}>{item.name}</div>
                      <div style={{ fontSize: 12, color: '#10b981', fontWeight: 700 }}>₹{item.price} × {item.quantity} = ₹{item.price * item.quantity}</div>
                    </div>
                    <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                      <button onClick={() => updateQty(item.medicineId, item.quantity - 1)} style={{ width: 28, height: 28, borderRadius: '50%', border: 'none', background: 'rgba(239,68,68,0.1)', color: '#ef4444', cursor: 'pointer', fontWeight: 800 }}>−</button>
                      <span style={{ fontWeight: 700, color: t.text, minWidth: 24, textAlign: 'center' }}>{item.quantity}</span>
                      <button onClick={() => updateQty(item.medicineId, item.quantity + 1)} style={{ width: 28, height: 28, borderRadius: '50%', border: 'none', background: 'rgba(8,145,178,0.1)', color: '#0891b2', cursor: 'pointer', fontWeight: 800 }}>+</button>
                      <button onClick={() => removeFromCart(item.medicineId)} style={{ width: 28, height: 28, borderRadius: '50%', border: 'none', background: 'rgba(239,68,68,0.1)', color: '#ef4444', cursor: 'pointer', fontSize: 12 }}>✕</button>
                    </div>
                  </div>
                ))}
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: 20, padding: '16px 0', borderTop: `2px solid ${t.cardBorder}` }}>
                  <span style={{ fontWeight: 800, color: t.text, fontSize: 17 }}>Total: <span style={{ color: '#10b981' }}>₹{total}</span></span>
                  <Btn variant="success" size="lg" onClick={() => { setBuyNowItem(null); setShowCheckout(true); }}>Proceed to Checkout →</Btn>
                </div>
              </>
            )}
          </div>
        )}

        {/* ORDERS */}
        {activeTab === 'orders' && (
          orders.length === 0 ? <div style={{ ...cardStyle(t) }}><EmptyState icon="📦" title="No orders yet" desc="Place your first medicine order" darkMode={darkMode} action={<Btn variant="primary" onClick={() => setActiveTab('shop')}>Shop Now</Btn>} /></div>
          : (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
              {orders.map(o => (
                <div key={o._id} style={{ ...cardStyle(t), padding: 22 }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 14 }}>
                    <div>
                      <div style={{ fontWeight: 700, color: t.text, fontSize: 15 }}>Order #{o._id?.slice(-6).toUpperCase()}</div>
                      <div style={{ fontSize: 12, color: t.textSub, marginTop: 3 }}>{new Date(o.createdAt).toLocaleString('en-IN', { dateStyle: 'medium', timeStyle: 'short' })}</div>
                    </div>
                    <StatusBadge status={o.status} darkMode={darkMode} />
                  </div>
                  <div style={{ marginBottom: 12 }}>
                    {o.items?.map((item, i) => <div key={i} style={{ fontSize: 13, color: t.textSub, marginBottom: 3 }}>• {item.name} × {item.quantity} — ₹{item.price * item.quantity}</div>)}
                  </div>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', borderTop: `1px solid ${t.cardBorder}`, paddingTop: 10 }}>
                    <span style={{ fontSize: 14, fontWeight: 800, color: '#10b981' }}>Total: ₹{o.totalAmount}</span>
                    <span style={{ fontSize: 12, color: t.textSub }}>📍 {o.deliveryAddress}</span>
                  </div>
                </div>
              ))}
            </div>
          )
        )}
      </div>

      {/* Checkout Modal */}
      <Modal isOpen={showCheckout} onClose={() => { setShowCheckout(false); setBuyNowItem(null); }} title={buyNowItem ? '⚡ Quick Buy' : '🛒 Checkout'} darkMode={darkMode} maxWidth={500}>
        <div style={{ marginBottom: 20 }}>
          <h4 style={{ color: t.text, marginBottom: 12 }}>Order Summary</h4>
          {checkoutItems.map(item => <div key={item.medicineId} style={{ display: 'flex', justifyContent: 'space-between', fontSize: 13, color: t.textSub, marginBottom: 6 }}><span>{item.name} × {item.quantity}</span><span style={{ color: t.text, fontWeight: 600 }}>₹{item.price * item.quantity}</span></div>)}
          <div style={{ borderTop: `1px solid ${t.cardBorder}`, marginTop: 10, paddingTop: 10, display: 'flex', justifyContent: 'space-between', fontWeight: 800, color: t.text }}>
            <span>Total</span><span style={{ color: '#10b981' }}>₹{checkoutTotal}</span>
          </div>
        </div>
        <div style={{ marginBottom: 14 }}>
          <label style={{ display: 'block', fontSize: 12, fontWeight: 700, color: t.textSub, marginBottom: 7, textTransform: 'uppercase' }}>Delivery Address *</label>
          <textarea value={address} onChange={e => setAddress(e.target.value)} placeholder="Enter full delivery address..." style={{ ...inp, minHeight: 80, resize: 'none', marginBottom: 0 }} required />
        </div>
        <div style={{ marginBottom: 20 }}>
          <label style={{ display: 'block', fontSize: 12, fontWeight: 700, color: t.textSub, marginBottom: 7, textTransform: 'uppercase' }}>Delivery Notes (Optional)</label>
          <input value={notes} onChange={e => setNotes(e.target.value)} placeholder="e.g. Call before delivery" style={{ ...inp, marginBottom: 0 }} />
        </div>
        <div style={{ background: 'rgba(245,158,11,0.08)', borderRadius: 10, padding: '10px 14px', marginBottom: 20, fontSize: 13, color: '#d97706', border: '1px solid rgba(245,158,11,0.2)' }}>
          💳 Payment on delivery · Est. 1-2 business days
        </div>
        <Btn variant="success" disabled={placing} style={{ width: '100%' }} onClick={placeOrder}>
          {placing ? '⏳ Placing Order...' : '✅ Place Order (₹' + checkoutTotal + ')'}
        </Btn>
      </Modal>
    </div>
  );
}
